using HealthDataExportTools;\nusing HealthDataExportTools.Configuration;\nusing HealthDataExportTools.Domain.Enums;\n\nnamespace HealthDataExportTools.Examples\n{\n    /// Example 1: Basic Health Data Export\n    /// Demonstrates the simplest way to parse and export health data.\n    class BasicExportExample\n    {\n        static async Task Main(string[] args)\n        {\n            try\n            {\n                Console.WriteLine("☕ Parsing health data from export.zip...");\n                var parser = new HealthDataParserService();\n                var healthData = await parser.ParseHealthDataAsync("export.zip").ConfigureAwait(false);\n                Console.WriteLine($"✅ Parsed {healthData.GetTotalRecordCount()} records\n");\n                \n                Console.WriteLine("☕ Exporting data to JSON format...");\n                var exporter = new ExportService();\n                await exporter.ExportCompleteAsync(healthData, "./output/", ExportFormat.Json).ConfigureAwait(false);\n                Console.WriteLine("✅ Export completed successfully!\n");\n                \n                Console.WriteLine("☕ Displaying output file information...");\n                var outputFile = "health_data.json";\n                if (File.Exists(outputFile))\n                {\n                    var fileInfo = new FileInfo(outputFile);\n                    Console.WriteLine($"☕ Output File: {Path.GetFullPath(outputFile)}");\n                    Console.WriteLine($"☕ Size: {fileInfo.Length / 1024.0:F2} KB\n");\n                }\n                \n                Console.WriteLine("✅ Example completed successfully!");\n            }\n            catch (Exception ex)\n            {\n                Console.WriteLine($"⚠ Error: {ex.Message}");\n                if (ex.InnerException != null)\n                    Console.WriteLine($" Details: {ex.InnerException.Message}");\n                Environment.Exit(1);\n            }\n        }\n    }\n}\n